using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private ServiceRegistry _registry = null!;

    [TestInitialize]
    public void Setup() => _registry = new ServiceRegistry();

    [TestMethod]
    public void Register_And_Resolve_Returns_Same_Instance()
    {
        var service = new DummyService();

        _registry.Register<IDummyService>(service);
        var resolved = _registry.Resolve<IDummyService>();

        Assert.AreSame(service, resolved);
    }

    [TestMethod]
    public void Resolve_Unregistered_Service_Returns_Null()
    {
        var result = _registry.Resolve<IDummyService>();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void ResolveRequired_Unregistered_Service_Throws()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _registry.ResolveRequired<IDummyService>());
    }

    [TestMethod]
    public void ResolveRequired_Registered_Service_Returns_Instance()
    {
        var service = new DummyService();
        _registry.Register<IDummyService>(service);

        var resolved = _registry.ResolveRequired<IDummyService>();

        Assert.AreSame(service, resolved);
    }

    [TestMethod]
    public void Register_Null_Service_Throws()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _registry.Register<IDummyService>(null!));
    }

    [TestMethod]
    public void Register_Overwrites_Previous_Registration()
    {
        var first = new DummyService();
        var second = new DummyService();

        _registry.Register<IDummyService>(first);
        _registry.Register<IDummyService>(second);

        Assert.AreSame(second, _registry.Resolve<IDummyService>());
    }

    [TestMethod]
    public void Clear_Removes_All_Services()
    {
        _registry.Register<IDummyService>(new DummyService());
        _registry.Register<IAnotherService>(new AnotherService());

        _registry.Clear();

        Assert.AreEqual(0, _registry.GetAll().Count);
    }

    [TestMethod]
    public void Clear_Makes_Previously_Registered_Service_Unresolvable()
    {
        _registry.Register<IDummyService>(new DummyService());

        _registry.Clear();

        Assert.IsNull(_registry.Resolve<IDummyService>());
    }

    [TestMethod]
    public void Remove_Makes_Service_Unresolvable()
    {
        _registry.Register<IDummyService>(new DummyService());

        _registry.Remove<IDummyService>();

        Assert.IsNull(_registry.Resolve<IDummyService>());
    }

    [TestMethod]
    public void Remove_Does_Not_Affect_Other_Services()
    {
        var other = new AnotherService();
        _registry.Register<IDummyService>(new DummyService());
        _registry.Register<IAnotherService>(other);

        _registry.Remove<IDummyService>();

        Assert.AreSame(other, _registry.Resolve<IAnotherService>());
    }

    [TestMethod]
    public void GetAll_Returns_All_Registered_Services()
    {
        var dummy = new DummyService();
        var another = new AnotherService();
        _registry.Register<IDummyService>(dummy);
        _registry.Register<IAnotherService>(another);

        var all = _registry.GetAll();

        Assert.AreEqual(2, all.Count);
        CollectionAssert.Contains(all.ToList(), dummy);
        CollectionAssert.Contains(all.ToList(), another);
    }

    // Test doubles
    private interface IDummyService;
    private interface IAnotherService;
    private sealed class DummyService : IDummyService;
    private sealed class AnotherService : IAnotherService;
}

